import { gomokuDirections, leftHalfGomokuDirectionTypes } from '../solution/constant'
import type { IGomokuBoard, IGomokuDirCountMap } from '../types'

let _gomokuDirCountMap: IGomokuDirCountMap | null = null
const getGomokuDirCountMap = (GOMOKU_SIZE: number): IGomokuDirCountMap => {
  const size: number = GOMOKU_SIZE * GOMOKU_SIZE
  if (_gomokuDirCountMap === null || _gomokuDirCountMap.length !== size) {
    _gomokuDirCountMap = new Uint32Array(size)
  }
  return _gomokuDirCountMap
}

export function calcGomokuDirCountMap(
  GOMOKU_SIZE: number,
  board: IGomokuBoard,
  dir: Readonly<[dr: number, dc: number]>,
): IGomokuDirCountMap {
  const [dr, dc] = dir
  const countMap: IGomokuDirCountMap = getGomokuDirCountMap(GOMOKU_SIZE)

  for (let r = 0; r < GOMOKU_SIZE; ++r) {
    const r0: number = r + dr
    const R0: number = r0 * GOMOKU_SIZE
    const R: number = r * GOMOKU_SIZE

    for (let c = 0; c < GOMOKU_SIZE; ++c) {
      const player: number = board[R + c]
      if (player) {
        const c0: number = c + dc
        let cnt = 1
        if (
          r0 >= 0 &&
          r0 < GOMOKU_SIZE &&
          c0 >= 0 &&
          c0 < GOMOKU_SIZE &&
          board[R0 + c0] === player
        ) {
          cnt += countMap[R0 + c0]
        }
        countMap[R + c] = cnt
      } else countMap[R + c] = 0
      continue
    }
  }
  return countMap
}

/**
 * Check if the game completed.
 * @param GOMOKU_SIZE
 * @param board
 * @param targetCount
 * @returns
 */
export function checkCompleted(GOMOKU_SIZE: number, board: IGomokuBoard, targetCount = 5): boolean {
  return leftHalfGomokuDirectionTypes.some(dirType => {
    const countMap = calcGomokuDirCountMap(GOMOKU_SIZE, board, gomokuDirections[dirType])
    return countMap.some(cnt => cnt >= targetCount)
  })
}
