import type { IGomokuState } from '@kyokuya/react-game-gomoku-core'
import { GomokuContextProvider } from '@kyokuya/react-game-gomoku-core'
import { createLocalStorage, useInitialData } from '@kyokuya/react-storage'
import CircularProgress from '@mui/material/CircularProgress'
import PropTypes from 'prop-types'
import React from 'react'
import { GamePersistState } from './component/GamePersistState'
import { GomokuGameMain } from './GomokuGameMain'

export interface IGomokuGameProps {
  storageKey?: string
  initialState?: Partial<IGomokuState>
}

export const GomokuGame: React.FC<IGomokuGameProps> = props => {
  const { storageKey, initialState: initialContextData } = props
  const storage = React.useMemo(
    () => (storageKey ? createLocalStorage<Partial<IGomokuState>>(storageKey, JSON) : null),
    [storageKey],
  )

  const initialState = useInitialData<Partial<IGomokuState>>(storage, initialContextData ?? {})
  if (initialState === null) {
    return <CircularProgress />
  }

  return (
    <GomokuContextProvider initialState={initialState}>
      <GamePersistState storage={storage} />
      <GomokuGameMain />
    </GomokuContextProvider>
  )
}

GomokuGame.propTypes = {
  storageKey: PropTypes.string,
  initialState: PropTypes.any,
}
